import React, { useEffect, useState } from 'react';
import axios from 'axios';
import {
  Container,
  TextField,
  MenuItem,
  Button,
  Typography,
  Box,
  Paper
} from '@mui/material';

function App() {
  const [clinics, setClinics] = useState([]);

  const [form, setForm] = useState({
    clinic_id: '',
    city: '',
    state: '',
    region: '',
    patient_name: '',
    phone: '',
    channel: '',
    service_type: '',
    description: ''
  });

  // 🔥 CARREGAR CLÍNICAS DO BACKEND
  useEffect(() => {
    axios.get('http://localhost:3001/clinics')
      .then(res => setClinics(res.data))
      .catch(err => console.error(err));
  }, []);

  // 🔥 ENVIO DO FORMULÁRIO
  const handleSubmit = async () => {
    try {
      await axios.post('http://localhost:3001/complaints', form);
      alert('Reclamação salva com sucesso!');

      setForm({
        clinic_id: '',
        city: '',
        state: '',
        region: '',
        patient_name: '',
        phone: '',
        channel: '',
        service_type: '',
        description: ''
      });

    } catch (error) {
      console.error(error);
      alert('Erro ao salvar');
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} style={{ padding: 30, marginTop: 40 }}>
        <Typography variant="h5" gutterBottom>
          Cadastro de Reclamação
        </Typography>

        {/* 🔥 CLÍNICA COM AUTO PREENCHIMENTO */}
        <TextField
          select
          label="Clínica"
          fullWidth
          margin="normal"
          value={form.clinic_id}
          onChange={(e) => {
            const clinic = clinics.find(c => c.id === parseInt(e.target.value));

            if (clinic) {
              setForm({
                ...form,
                clinic_id: clinic.id,
                city: clinic.city,
                state: clinic.state,
                region: clinic.region
              });
            }
          }}
        >
          {clinics.map((c) => (
            <MenuItem key={c.id} value={c.id}>
              {c.name}
            </MenuItem>
          ))}
        </TextField>

        {/* 🔥 AUTO PREENCHIDOS */}
        <TextField
          label="Cidade"
          value={form.city}
          fullWidth
          margin="normal"
          disabled
        />

        <TextField
          label="Estado"
          value={form.state}
          fullWidth
          margin="normal"
          disabled
        />

        <TextField
          label="Região"
          value={form.region}
          fullWidth
          margin="normal"
          disabled
        />

        {/* 🔥 DADOS DO PACIENTE */}
        <TextField
          label="Nome do paciente"
          fullWidth
          margin="normal"
          value={form.patient_name}
          onChange={(e) => setForm({ ...form, patient_name: e.target.value })}
        />

        <TextField
          label="Telefone"
          fullWidth
          margin="normal"
          value={form.phone}
          onChange={(e) => setForm({ ...form, phone: e.target.value })}
        />

        {/* 🔥 CANAL COMPLETO */}
        <TextField
  select
  label="Canal"
  fullWidth
  margin="normal"
  value={form.channel}
  onChange={(e) => setForm({ ...form, channel: e.target.value })}
>
  <MenuItem value="whatsapp">WhatsApp</MenuItem>
  <MenuItem value="email">Email</MenuItem>
  <MenuItem value="phone">Telefone</MenuItem>
  <MenuItem value="google">Google</MenuItem>
  <MenuItem value="facebook">Facebook</MenuItem>
  <MenuItem value="instagram">Instagram</MenuItem>
  <MenuItem value="reclame_aqui">Reclame Aqui</MenuItem>
  <MenuItem value="nps">NPS</MenuItem>
</TextField>

        {/* 🔥 SERVIÇO */}
        <TextField
          select
          label="Tipo de serviço"
          fullWidth
          margin="normal"
          value={form.service_type}
          onChange={(e) => setForm({ ...form, service_type: e.target.value })}
        >
          <MenuItem value="clinico">Clínico Geral</MenuItem>
          <MenuItem value="ortodontia">Ortodontia</MenuItem>
          <MenuItem value="implante">Implante</MenuItem>
          <MenuItem value="endodontia">Endodontia</MenuItem>
        </TextField>

        {/* 🔥 DESCRIÇÃO */}
        <TextField
          label="Descrição"
          multiline
          rows={4}
          fullWidth
          margin="normal"
          value={form.description}
          onChange={(e) => setForm({ ...form, description: e.target.value })}
        />

        {/* 🔥 BOTÃO */}
        <Box mt={2}>
          <Button variant="contained" fullWidth onClick={handleSubmit}>
            Salvar
          </Button>
        </Box>
      </Paper>
    </Container>
  );
}

export default App;
